function NavItem({ item, active, onNav, onOpenModal }) {
  const isLocked = !!item.locked;
  const handleClick = () => {
    if (isLocked) onOpenModal(item.locked);
    else onNav(item.id);
  };

  return (
    <div
      onClick={handleClick}
      style={{
        display: 'flex', alignItems: 'center', gap: 9, padding: '8px 10px',
        borderRadius: 7, fontSize: 13,
        color: active ? 'var(--in2)' : isLocked ? 'var(--dim)' : 'var(--tx2)',
        cursor: 'pointer', marginBottom: 1, transition: 'all .15s',
        userSelect: 'none',
        background: active ? 'rgba(99,102,241,.18)' : 'transparent',
        fontWeight: active ? 600 : 400,
      }}
      onMouseEnter={e => { if (!active) e.currentTarget.style.background = 'var(--s1)'; }}
      onMouseLeave={e => { if (!active) e.currentTarget.style.background = 'transparent'; }}
    >
      <span style={{ width: 15, textAlign: 'center', flexShrink: 0 }}>{item.icon}</span>
      <span style={{ flex: 1 }}>{item.label}</span>
      {item.badge && (
        <span style={{ padding: '2px 7px', borderRadius: 10, fontSize: 10, fontWeight: 600, background: 'var(--rd)', color: '#fff' }}>
          {item.badge}
        </span>
      )}
      {isLocked && (
        <span style={{ fontSize: 10, opacity: .6 }}>
          {item.locked === 'prime' ? '👑' : '🔒'}
        </span>
      )}
    </div>
  );
}

function TierBadge({ style, label, onClick }) {
  const styles = {
    free:   { background: 'rgba(148,163,184,.12)', border: '1px solid rgba(148,163,184,.2)', color: 'var(--mu)' },
    growth: { background: 'rgba(99,102,241,.15)',  border: '1px solid rgba(99,102,241,.3)',  color: 'var(--in2)' },
    prime:  { background: 'linear-gradient(90deg,rgba(245,158,11,.2),rgba(251,191,36,.12))', border: '1px solid rgba(245,158,11,.3)', color: 'var(--go2)' },
  };
  return (
    <div
      onClick={onClick}
      style={{ display: 'inline-flex', alignItems: 'center', marginTop: 7, padding: '3px 10px', borderRadius: 20, fontSize: 11, fontWeight: 600, cursor: 'pointer', transition: 'opacity .15s', ...styles[style] }}
    >
      {label}
    </div>
  );
}
